const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const to = body.to;
const subject = body.subject;
const message = body.message || body.text || '';
const html = body.html || '';
const cc = body.cc || '';
const bcc = body.bcc || '';

if (!tenantId || !to || !subject) {
  return [{ json: { success: false, error: 'tenantId, to et subject requis' } }];
}

return [{ json: { tenantId, to, subject, message, html, cc, bcc, valid: true } }];

const data = $('02. Valider').first().json;
const configRow = $input.first().json;
const config = configRow?.config || {};
const fromName = config.fromName || 'TalosPrimes';
const fromEmail = config.email || '';
const signature = config.signature || '';
const fullMessage = signature ? data.message + '\n\n' + signature : data.message;

// Generer le HTML professionnel a partir du texte brut
const textContent = data.message || '';
const paragraphs = textContent.split(/\n\n|\n/).filter(p => p.trim()).map(p => '<p style="margin:0 0 16px;font-size:15px;color:#2d3748;line-height:1.7;">' + p.trim() + '</p>').join('');

const htmlEmail = '<div style="margin:0;padding:0;background-color:#f4f6f9;font-family:Segoe UI,Roboto,Arial,sans-serif;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background-color:#f4f6f9;padding:30px 0;"><tr><td align="center"><table role="presentation" width="600" cellpadding="0" cellspacing="0" style="max-width:600px;width:100%;background-color:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.08);"><tr><td style="background:linear-gradient(135deg,#1a1a2e 0%,#16213e 50%,#0f3460 100%);padding:28px 40px;text-align:center;"><h1 style="margin:0;font-size:24px;font-weight:700;color:#ffffff;letter-spacing:1px;">' + fromName + '</h1><p style="margin:4px 0 0;font-size:12px;color:#8b9cc7;letter-spacing:2px;text-transform:uppercase;">Gestion d\'entreprise intelligente</p></td></tr><tr><td style="padding:36px 40px 28px;">' + paragraphs + '</td></tr><tr><td style="padding:0 40px 30px;"><table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td style="border-top:1px solid #e8ecf1;padding-top:24px;"><p style="margin:0 0 4px;font-size:14px;font-weight:600;color:#1a1a2e;">L\'equipe ' + fromName + '</p><p style="margin:0;font-size:12px;color:#6b7c93;">' + (fromEmail || 'direction@talosprimes.com') + ' | talosprimes.com</p></td></tr></table></td></tr><tr><td style="background-color:#f8f9fb;padding:16px 40px;text-align:center;border-top:1px solid #e8ecf1;"><p style="margin:0;font-size:11px;color:#9ba8b7;">Ce message a ete envoye automatiquement. Pour toute question, repondez directement a cet email.</p></td></tr></table></td></tr></table></div>';

// Si l'appelant a deja fourni du HTML custom, l'utiliser; sinon generer depuis le texte
const finalHtml = data.html || htmlEmail;

return [{ json: { ...data, fromName, fromEmail, signature, fullMessage, htmlBody: finalHtml, config } }];

const data = $('04. Preparer').first().json;
const result = $input.first().json;

return [{ json: {
  success: true,
  data: {
    message: 'Email envoye avec succes',
    messageId: result.id || null,
    to: data.to,
    subject: data.subject
  }
} }];
